import { By } from "selenium-webdriver";
import ojwd, { DriverLike, register } from "../../";
import { OjTextArea } from "./OjTextArea";
export { OjTextArea };

/**
 * Create an instance of [[OjTextArea]].  This function will first wait for
 * the element to appear in the DOM before trying to locate it.
 * @example
 * <code>
 * const el = await ojTextArea(driver, By.id('my-oj-text-area'))
 * </code>
 * @param driver A WebDriver/WebElement instance used to locate the component
 * element.
 * @param by The By locator with which to find the element
 */
export async function ojTextArea(driver: DriverLike, by: By): Promise<OjTextArea> {
  const webEl = await driver.findElement(by);
  // Check that the element is of type OjTextArea
  if (!(webEl instanceof OjTextArea)) {
    const tagName = await webEl.getTagName();
    throw Error(`Locator '${by}' located a <${tagName}>, but expected <oj-text-area>`);
  }
  return webEl;
}

register("oj-text-area", OjTextArea);
